"""Generic async event stream with a final result.

Port of hoocode's `packages/ai/src/utils/event-stream.ts`.
"""

from __future__ import annotations

import asyncio
from collections.abc import AsyncIterator, Callable
from typing import Generic, TypeVar

from cortex.ai.types import AssistantMessage, AssistantMessageEvent

T = TypeVar("T")
R = TypeVar("R")

_END = object()  # sentinel: a waiter woke up because the stream ended


class EventStream(Generic[T, R]):
    """Async-iterable queue of events that resolves to a final result.

    Producers call `push()` for each event and `end()` once no more events
    will be pushed. Consumers iterate with `async for` and can await
    `result()` to get the final value (derived from the completing event, or
    from an explicit `end(result)`).
    """

    def __init__(
        self,
        is_complete: Callable[[T], bool],
        extract_result: Callable[[T], R],
    ) -> None:
        self._is_complete = is_complete
        self._extract_result = extract_result
        self._queue: list[T] = []
        self._waiting: list[asyncio.Future[object]] = []
        self._done = False
        self._final_result_future: asyncio.Future[R] = asyncio.get_running_loop().create_future()

    def push(self, event: T) -> None:
        if self._done:
            return

        if self._is_complete(event):
            self._done = True
            if not self._final_result_future.done():
                self._final_result_future.set_result(self._extract_result(event))

        # Deliver to waiting consumer or queue it
        if self._waiting:
            waiter = self._waiting.pop(0)
            if not waiter.done():
                waiter.set_result(event)
        else:
            self._queue.append(event)

    def end(self, result: R | None = None) -> None:
        self._done = True
        if result is not None and not self._final_result_future.done():
            self._final_result_future.set_result(result)
        # Notify all waiting consumers that we're done
        while self._waiting:
            waiter = self._waiting.pop(0)
            if not waiter.done():
                waiter.set_result(_END)

    def __aiter__(self) -> AsyncIterator[T]:
        return self._iterate()

    async def _iterate(self) -> AsyncIterator[T]:
        while True:
            if self._queue:
                yield self._queue.pop(0)
            elif self._done:
                return
            else:
                waiter: asyncio.Future[object] = asyncio.get_running_loop().create_future()
                self._waiting.append(waiter)
                value = await waiter
                if value is _END:
                    return
                yield value  # type: ignore[misc]

    async def result(self) -> R:
        return await self._final_result_future


class AssistantMessageEventStream(EventStream[AssistantMessageEvent, AssistantMessage]):
    """Event stream specialized for `AssistantMessageEvent` → `AssistantMessage`."""

    def __init__(self) -> None:
        def is_complete(event: AssistantMessageEvent) -> bool:
            return event.type in ("done", "error")

        def extract_result(event: AssistantMessageEvent) -> AssistantMessage:
            if event.type == "done":
                return event.message
            if event.type == "error":
                return event.error
            raise ValueError("Unexpected event type for final result")

        super().__init__(is_complete, extract_result)


def create_assistant_message_event_stream() -> AssistantMessageEventStream:
    """Factory function for `AssistantMessageEventStream` (for use in extensions)."""
    return AssistantMessageEventStream()

"""API provider registry.

Mechanical port of hoocode's `packages/ai/src/api-registry.ts`.
"""

from __future__ import annotations

from typing import Any

from cortex.ai.types import Api, Context, Model


class StreamFunction:
    """Callable that produces an event stream."""

    def __call__(
        self,
        model: Model,
        context: Context,
        options: dict[str, Any] | None = None,
    ) -> Any: ...


class ApiProvider:
    """Registered API provider with stream and streamSimple functions."""

    def __init__(
        self,
        api: Api,
        stream: StreamFunction,
        stream_simple: StreamFunction,
    ) -> None:
        self.api = api
        self.stream = stream
        self.stream_simple = stream_simple


class RegisteredApiProvider:
    """Internal registry entry."""

    def __init__(
        self,
        provider: ApiProvider,
        source_id: str | None = None,
    ) -> None:
        self.provider = provider
        self.source_id = source_id


# Global registry
_api_provider_registry: dict[str, RegisteredApiProvider] = {}


def _wrap_stream(api: Api, stream: StreamFunction) -> StreamFunction:
    """Wrap a stream function to validate api matches."""

    def wrapped(
        model: Model,
        context: Context,
        options: dict[str, Any] | None = None,
    ) -> Any:
        if model.api != api:
            raise ValueError(f"Mismatched api: {model.api} expected {api}")
        return stream(model, context, options)

    return wrapped  # type: ignore


def _wrap_stream_simple(api: Api, stream_simple: StreamFunction) -> StreamFunction:
    """Wrap a streamSimple function to validate api matches."""

    def wrapped(
        model: Model,
        context: Context,
        options: dict[str, Any] | None = None,
    ) -> Any:
        if model.api != api:
            raise ValueError(f"Mismatched api: {model.api} expected {api}")
        return stream_simple(model, context, options)

    return wrapped  # type: ignore


def register_api_provider(
    provider: ApiProvider,
    source_id: str | None = None,
) -> None:
    """Register an API provider."""
    wrapped = ApiProvider(
        api=provider.api,
        stream=_wrap_stream(provider.api, provider.stream),
        stream_simple=_wrap_stream_simple(provider.api, provider.stream_simple),
    )
    _api_provider_registry[provider.api] = RegisteredApiProvider(
        provider=wrapped,
        source_id=source_id,
    )


def get_api_provider(api: str) -> ApiProvider | None:
    """Get a registered API provider by api name."""
    entry = _api_provider_registry.get(api)
    return entry.provider if entry else None


def get_api_providers() -> list[ApiProvider]:
    """Get all registered API providers."""
    return [entry.provider for entry in _api_provider_registry.values()]


def unregister_api_providers(source_id: str) -> None:
    """Unregister all API providers from a specific source."""
    to_remove = [
        api for api, entry in _api_provider_registry.items() if entry.source_id == source_id
    ]
    for api in to_remove:
        del _api_provider_registry[api]


def clear_api_providers() -> None:
    """Clear all registered API providers."""
    _api_provider_registry.clear()

